import React, { useState } from 'react';
import { Link, Outlet, useNavigate } from 'react-router-dom';
import { useAuth } from '../../components/AuthContext';
import './AdminLayout.css';

const AdminLayout = () => {
    const [sidebarOpen, setSidebarOpen] = useState(true);
    const { user, logout } = useAuth();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/');
    };

    const toggleSidebar = () => {
        setSidebarOpen(!sidebarOpen);
    };

    const menuItems = [
        { path: '/admin', icon: '📊', label: 'Dashboard' },
        { path: '/admin/orders', icon: '📦', label: 'Quản lý đơn hàng' },
        { path: '/admin/cars', icon: '🚗', label: 'Quản lý xe' },
        { path: '/admin/users', icon: '👥', label: 'Quản lý người dùng' },
        { path: '/admin/testdrives', icon: '📅', label: 'Lịch lái thử' },
        { path: '/admin/reviews', icon: '⭐', label: 'Đánh giá' },
        { path: '/admin/contacts', icon: '📧', label: 'Liên hệ' },
        { path: '/admin/news', icon: '📰', label: 'Tin tức' },
    ];

    return (
        <div className="admin-layout">
            {/* Sidebar */}
            <div className={`sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
                <div className="sidebar-header">
                    <h2>{sidebarOpen ? 'AutoVip Admin' : 'AV'}</h2>
                    <button onClick={toggleSidebar} className="toggle-sidebar">
                        {sidebarOpen ? '◀' : '▶'}
                    </button>
                </div>
                
                {sidebarOpen && (
                    <div className="admin-info">
                        <div className="admin-avatar">👨‍💼</div>
                        <div className="admin-details">
                            <p>Xin chào,</p>
                            <strong>{user?.fullname}</strong>
                            <span className="admin-badge">Admin</span>
                        </div>
                    </div>
                )}
                
                <nav className="sidebar-nav">
                    {menuItems.map((item, index) => (
                        <Link key={index} to={item.path} className="nav-item">
                            <span className="nav-icon">{item.icon}</span>
                            {sidebarOpen && <span className="nav-label">{item.label}</span>}
                        </Link>
                    ))}
                </nav>
                
                <div className="sidebar-footer">
                    <Link to="/" className="nav-item">
                        <span className="nav-icon">🏠</span>
                        {sidebarOpen && <span className="nav-label">Về trang chủ</span>}
                    </Link>
                    <button onClick={handleLogout} className="nav-item logout-btn">
                        <span className="nav-icon">🚪</span>
                        {sidebarOpen && <span className="nav-label">Đăng xuất</span>}
                    </button>
                </div>
            </div>
            
            {/* Main Content */}
            <div className={`main-content ${sidebarOpen ? '' : 'expanded'}`}>
                <Outlet />
            </div>
        </div>
    );
};

export default AdminLayout;
